            menuIcon.id = "menu";
            menuIcon.textContent = "menu";
    navBar.appendChild(menuIcon);
        const navLinks = document.createElement("div");
            navLinks.className = "nav-links";
                const home = document.createElement("div")
                    home.className = "nav-home";
