                                departmentsSubLink4.href = "departments.html#department4";
                                departmentsSubLink4.textContent = "Windows & Doors";
                            departmentsDropdownContent.appendChild(departmentsSubLink4);
                            const departmentsSubLink5 = document.createElement("a");
                                departmentsSubLink5.href = "departments.html#department5";
                                departmentsSubLink5.textContent = "Water Tanks";
                            departmentsDropdownContent.appendChild(departmentsSubLink5);
                            const departmentsSubLink6 = document.createElement("a");
                                departmentsSubLink6.href = "departments.html#department6";
                                departmentsSubLink6.textContent = "Roofing Materials";
                            departmentsDropdownContent.appendChild(departmentsSubLink6);
                            const departmentsSubLink7 = document.createElement("a");
                                departmentsSubLink7.href = "departments.html#department7";
                                departmentsSubLink7.textContent = "Glass";
                            departmentsDropdownContent.appendChild(departmentsSubLink7);
                            const departmentsSubLink8 = document.createElement("a");
                                departmentsSubLink8.href = "departments.html#department8";
                                departmentsSubLink8.textContent = "Household Paint";
                            departmentsDropdownContent.appendChild(departmentsSubLink8);
                            const departmentsSubLink9 = document.createElement("a");
                                departmentsSubLink9.href = "departments.html#department9";
                                departmentsSubLink9.textContent = "Electrical";
                            departmentsDropdownContent.appendChild(departmentsSubLink9);
                            const departmentsSubLink10 = document.createElement("a");
                                departmentsSubLink10.href = "departments.html#department10";
                                departmentsSubLink10.textContent = "Plumbing Fixtures & Accessories";
                            departmentsDropdownContent.appendChild(departmentsSubLink10);
                    departments.appendChild(departmentsDropdownContent);
        navLinks.appendChild(departments);
            const services = document.createElement("div")
                services.className = "nav-services dropdown";
                const servicesLink = document.createElement("a");
                    servicesLink.href = "services.html";
                    servicesLink.textContent = "SERVICES";
                    servicesLink.className = "services-link";
                services.appendChild(servicesLink);
                const servicesDropdownContent = document.createElement("div");
                    servicesDropdownContent.className = "dropdown-content";
                        const servicesSubLink1 = document.createElement("a");
                            servicesSubLink1.href = "services.html#service1";
                            servicesSubLink1.textContent = "Material Handling";
                        servicesDropdownContent.appendChild(servicesSubLink1);
                        const servicesSubLink2 = document.createElement("a");
                            servicesSubLink2.href = "services.html#service2";
                            servicesSubLink2.textContent = "Paint Color Matching";
                        servicesDropdownContent.appendChild(servicesSubLink2);
                        const servicesSubLink3 = document.createElement("a");
                            servicesSubLink3.href = "services.html#service3";
                            servicesSubLink3.textContent = "Customs Brokerage";
                        servicesDropdownContent.appendChild(servicesSubLink3);
                services.appendChild(servicesDropdownContent);
        navLinks.appendChild(services);
            const about = document.createElement("div")
                about.className = "nav-about";
                const aboutLink = document.createElement("a");
                    aboutLink.href = "about.html";
                    aboutLink.textContent = "ABOUT US";
                    aboutLink.className = "about-link";
                about.appendChild(aboutLink);
        navLinks.appendChild(about);
            const contact = document.createElement("div")
                contact.className = "nav-contact dropdown";
                const contactLink = document.createElement("a");
                    contactLink.href = "contact.html";
                    contactLink.textContent = "CONTACT US";
                    contactLink.className = "contact-link";
                contact.appendChild(contactLink);
        navLinks.appendChild(contact);
    navBar.appendChild(navLinks);
navContainer.appendChild(navBar);

const menu = document.querySelector("#menu");
menu.addEventListener("click", () => {
  const navLinks = document.querySelector(".nav-links");
  navLinks.classList.toggle("active");
});

